import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.CnqOxlWO.js";const p=JSON.parse('{"title":"Settings","description":"","frontmatter":{},"headers":[],"relativePath":"settings/overview.md","filePath":"settings/overview.md","lastUpdated":1773376681000}'),n={name:"settings/overview.md"};function i(s,e,l,h,u,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>The Settings page is where you manage your account, customize appearance, and control updates.</p><h2 id="account" tabindex="-1">Account <a class="header-anchor" href="#account" aria-label="Permalink to &quot;Account&quot;">​</a></h2><p>If you are logged in, the Account section shows:</p><ul><li><strong>Email</strong> — the email address associated with your account</li><li><strong>Nickname</strong> — if you have set one</li><li><strong>Plan</strong> — your current subscription tier (e.g., Free)</li><li><strong>Credit Balance</strong> — how many credits you have remaining, with a <strong>Recharge</strong> button to top up</li><li><strong>Plan Expiry</strong> — when your current plan expires (if applicable)</li></ul><h3 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h3><ul><li><strong>Refresh</strong> — re-fetches your account info and credit balance from the server</li><li><strong>Logout</strong> — signs you out and returns to the login page</li></ul><h2 id="appearance" tabindex="-1">Appearance <a class="header-anchor" href="#appearance" aria-label="Permalink to &quot;Appearance&quot;">​</a></h2><h3 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h3><p>Three options:</p><ul><li><strong>Light</strong> — light background</li><li><strong>Dark</strong> — dark background</li><li><strong>System</strong> — follows your operating system&#39;s theme setting</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>Three languages are supported:</p><ul><li>English</li><li>Chinese</li><li>Japanese</li></ul><p>The language change takes effect immediately across the entire app.</p><h2 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h2><p>A compact card between Appearance and Updates that shows:</p><ul><li><strong>App version</strong> — the currently installed version of ClawdSaber</li><li><strong>Website</strong> — opens the official website</li><li><strong>Telegram</strong> — opens the Telegram community</li><li><strong>Twitter</strong> — opens the Twitter/X page</li></ul><p>All links open in your default browser.</p><h2 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h2><h3 id="current-version" tabindex="-1">Current Version <a class="header-anchor" href="#current-version" aria-label="Permalink to &quot;Current Version&quot;">​</a></h3><p>Displays the version you are currently running, along with update status information.</p><h3 id="update-controls" tabindex="-1">Update Controls <a class="header-anchor" href="#update-controls" aria-label="Permalink to &quot;Update Controls&quot;">​</a></h3><ul><li><strong>Check for Updates</strong> — manually check whether a newer version is available</li><li><strong>Download Update</strong> — download an available update</li><li><strong>Install &amp; Restart</strong> — install a downloaded update and restart the app</li></ul><h3 id="automatic-options" tabindex="-1">Automatic Options <a class="header-anchor" href="#automatic-options" aria-label="Permalink to &quot;Automatic Options&quot;">​</a></h3><ul><li><strong>Auto-check for updates</strong> — checks for updates every time the app starts</li><li><strong>Auto-download updates</strong> — downloads updates in the background automatically</li></ul><p>Updates are downloaded in the background and installed when you restart the app.</p><h2 id="top-level-controls" tabindex="-1">Top-Level Controls <a class="header-anchor" href="#top-level-controls" aria-label="Permalink to &quot;Top-Level Controls&quot;">​</a></h2><p>Some controls appear in the title bar rather than the Settings page:</p><h3 id="gateway-status-indicator" tabindex="-1">Gateway Status Indicator <a class="header-anchor" href="#gateway-status-indicator" aria-label="Permalink to &quot;Gateway Status Indicator&quot;">​</a></h3><p>The title bar shows the current Gateway status:</p><ul><li><strong>Running</strong> — the Gateway is active and ready</li><li><strong>Loading</strong> — the Gateway is starting up</li><li><strong>Error</strong> — something went wrong; check the FAQ</li><li><strong>Stopped</strong> — the Gateway is not running</li></ul><h3 id="memory-mode" tabindex="-1">Memory Mode <a class="header-anchor" href="#memory-mode" aria-label="Permalink to &quot;Memory Mode&quot;">​</a></h3><p>A brain icon in the title bar toggles memory mode. This is an optional feature for advanced users that enables the agent to recall information across sessions.</p>',34)])])}const g=a(n,[["render",i]]);export{p as __pageData,g as default};
